const cheapCount = 4;
const expensiveMaxCount = 1; // aantal dure uren voor max ontladen
const minSpread = 0.08;      // 8 cent boven gemiddelde goedkope uren

let uren = raw.data.map((item, index) => ({
    uur: index,
    prijs: Number(item.prijsZP)
})).filter(x => !isNaN(x.prijs));

if (uren.length === 0) {
    node.status({fill:'red',shape:'ring',text:'no valid prices'});
    return null;
}

let goedkoopstePrijs = Math.min(...uren.map(x => x.prijs));

let cheapHours = [...uren]
    .sort((a, b) => a.prijs - b.prijs)
    .slice(0, cheapCount)
    .sort((a, b) => a.uur - b.uur)
    .map(x => x.uur);

// Gemiddelde prijs van de gekozen goedkope uren berekenen
let cheapPrices = uren
    .filter(x => cheapHours.includes(x.uur))
    .map(x => x.prijs);

let cheapAvg = cheapPrices.length
    ? cheapPrices.reduce((a, b) => a + b, 0) / cheapPrices.length
    : goedkoopstePrijs;

// Duurste uur berekenen
let duurste = [...uren].sort((a, b) => b.prijs - a.prijs)[0];

let duursteUur = duurste.uur;
let duurstePrijs = duurste.prijs;
let spreadDuursteVsCheapAvg = duurstePrijs - cheapAvg;
let spreadDuursteVsGoedkoopste = duurstePrijs - goedkoopstePrijs;
let dischargeAllowed = spreadDuursteVsCheapAvg >= minSpread;

// Alleen het duurste uur kiezen als het genoeg boven cheapAvg ligt
