var invoerData = global.get("ZonneplanTijdsloten.data") || [];

var lijnPrijs = [];
var lijnPrijsZP = [];
var markerNu = [];

var nu = new Date();
nu.setMinutes(0, 0, 0);
var huidigUur = nu.getTime();

var huidigePrijs = null;
var minPrijs = Infinity;
var maxPrijs = -Infinity;

for (var i = 0; i < invoerData.length; i++) {
    var item = invoerData[i];

    var datum = new Date(item.datum);
    var timestamp = datum.getTime();

    var datumUur = new Date(item.datum);
    datumUur.setMinutes(0, 0, 0);
    var timestampUur = datumUur.getTime();

    var prijs = Number(item.prijs);
    var prijsZP = Number(item.prijsZP);

    lijnPrijs.push({ x: timestamp, y: prijs });
    lijnPrijsZP.push({ x: timestamp, y: prijsZP });

    if (!isNaN(prijs)) {
        minPrijs = Math.min(minPrijs, prijs);
        maxPrijs = Math.max(maxPrijs, prijs);
    }

    if (!isNaN(prijsZP)) {
        minPrijs = Math.min(minPrijs, prijsZP);
        maxPrijs = Math.max(maxPrijs, prijsZP);
    }

    if (timestampUur === huidigUur) {
        huidigePrijs = prijs;
    }
}

// verticale marker maken
if (huidigePrijs !== null && minPrijs !== Infinity && maxPrijs !== -Infinity) {
    markerNu.push({ x: huidigUur, y: minPrijs });
    markerNu.push({ x: huidigUur, y: maxPrijs });
}

msg.payload = [{
    series: ["Price", "Price All in", "Now"],
    data: [lijnPrijs, lijnPrijsZP, markerNu]
}];

if (huidigePrijs !== null && !isNaN(huidigePrijs)) {
    msg.ui_control = {
        options: {
            title: "Huidige prijs: " + Number(huidigePrijs).toFixed(2) + " ct/kWh"
        }
    };
}

return msg;
